window.__dh_data["cs"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "Dhammapada",
  "chaps": "Kapitoly",
  "fontsize": "Velikost písma",
  "chap1": "Dvojice",
  "1": "mysl je předchůdcem stavů, mysl je základem, mysl je tvůrcem, s myslí znečištěnou [zkaženou] kdo hovoří, kdo jedná, toho strast následuje jako kolo nohu tažného zvířete",
  "2": "mysl je předchůdcem stavů, mysl je základem, mysl je tvůrcem, s myslí čistou [povznešenou] kdo hovoří, kdo jedná, toho štěstí následuje jako věrný stín",
  "3": "'zhanil mě, zbil mě, přepadl mě a oloupil mě'u těch, kdo na tom prodlévají, jejich zášť se neutiší",
  "4": "'zhanil mě, zbil mě, přepadl mě a oloupil mě'u těch, kdo na tom neprodlévají, jejich zášť se utiší",
  "5": "nikoli nenávistí se nenávist kdy zde utiší, jen beznenávistností se utiší, takový je věčný stav věcí [zákon]",
  "6": "mnozí nevědí, že jednou musíme zemřít, avšak ti, kdo to vědí, utiší své spory",
  "7": "[tělesnou] krásu nazíraje, kdo prodlévá, své smysly nekontroluje, v jídle je nemírný, líný a ochablý, toho zkosí Mára, jako vítr slabý strom",
  "8": "[tělesnou] odpornost nazíraje, kdo prodlévá, své smysly dobře kontroluje, v jídle je umírněný, obdařen důvěrou a energický, toho nezkosí Mára, jako vítr kamennou skálu",
  "9": "kdo není zbaven mentálních nečistot a z oranžového roucha oděv si oblékne, postrádaje sebekontrolu a opravdovost, ten si nezasluhuje oranžové roucho",
  "10": "kdo však, byť není v oranžovém rouchu, je ctnostný a dobře soustředěný, obdařený sebekontrolou a opravdovostí, ten si zasluhuje oranžové roucho",
  "11": "ti, kdo nepodstatné považují za podstatné a podstatné vidí jako nepodstatné, ti k podstatě nedojdou, zastávajíce oblast špatného myšlení",
  "12": "ale ti, kdo podstatné jakožto podstatné rozpoznají a nepodstatné jakožto nepodstatné, ti k podstatě dojdou, zastávajíce oblast správného myšlení",
  "13": "jako do domu špatně pokrytého déšť pronikne, tak do nerozvinuté mysli vášeň pronikne",
  "14": "jako do domu dobře pokrytého déšť nepronikne, tak do dobře rozvinuté mysli vášeň nepronikne",
  "15": "v tomto světě se trápí, na onom světě se trápí, kdo koná zlo, v obou světech se trápí, trápí se a trpí, když obzírá své nečisté konání",
  "16": "v tomto světě se raduje, na onom světě se raduje, kdo koná dobro, v obou světech se raduje, raduje se a těší se, když obzírá své očištěné konání",
  "17": "v tomto světě je trýzněn, na onom světě je trýzněn, kdo koná zlo, v obou světech je trýzněn, při pomyšlení: 'konal jsem zlo' je trýzněn a ještě více je trýzněn, když dojde do strastného stavu bytí",
  "18": "v tomto světě je potěšen, na onom světě je potěšen, kdo koná dobro [zásluhy], v obou světech je potěšen, při pomyšlení: 'konal jsem dobro [zásluhy]' je potěšen a ještě více je potěšen, když dojde do šťastného stavu bytí",
  "19": "i když mnoho posvátné texty cituje, ale nekoná podle tohonedbalý člověk, jako pastýř sčítající krávy, jež patří jiným, ten nemá podíl na asketickém životě",
  "20": "i když málo posvátné texty cituje, ale následuje Dhammu a jedná v souladu s Dhammou, vášeň a nenávist odvrhl, i zaslepenost, jasně chápající, se správně osvobozenou myslí, nelpí na tomto ani na onom světě, ten ma podíl na asketickém životě",
  "chap2": "Dbalost",
  "21": "dbalost je cesta k bezsmrtnosti, nedbalost je cesta ke smrti, dbalí neumírají, ale nedbalci jsou již jakoby mrtví",
  "22": "tento rozdíl když pochopili, dbalí mudrcové, dbalostí se těší, v oblasti ušlechtilých se radují",
  "23": "ti v meditačním pohroužení setrvávající, stále s vytrvalým úsilím, tito mudrci dosáhnou odpoutání, nepřekonatelného vyproštění z jha",
  "24": "kdo je snaživý a má uvědomění, čistých činů uvážlivý vykonavatel, v kázni a v Dhammě žijící, tomuto dbalému sláva narůstá",
  "25": "snaživostí a dbalostí, sebekázní a sebeovládáním ostrov si vytvoří moudrý člověk jenž žádná záplava nezatopí",
  "26": "nedbalosti jsou oddaní pošetilí a hloupí lidé, svoji dbalost však moudrý člověk jako své nejlepší bohatství ochraňuje",
  "27": "neoddávejte se nedbalosti ani smyslnému potěšení intimností, ten, kdo je dbalý a dlí v meditačním pohroužení dosáhne rozsáhlejší blaženosti",
  "28": "nedbalost dbalostí když moudrý člověk vypudí, na věž moudrosti vystoupí, bez trápení pak na trápící se lidstvo, jako z vrcholku hory na zem, moudrý na pošetilé shlíží",
  "29": "dbalý mezi nedbalci, mezi ospalci zcela bdělý, jako před slabého koně rychlý kůň, stejně tak postupuje vpřed moudrý",
  "30": "dbalostí Maghavá mezi bohy prvenství došel, dbalost je chválena, nedbalost kritizována, vždy",
  "31": "dbalostí se těšící mnich, na nedbalost ve strachu hledící, pouta malá i velká v sobě spálí, jako požár když postupuje",
  "32": "dbalostí se těšící mnich, na nedbalost ve strachu hledící, je neschopen odpadnutí a je již v blízkosti odpoutání",
  "chap3": "Mysl",
  "33": "těkavou a rozechvělou mysl je těžké uhlídat, těžké zvládnout, srovná ji však ten, kdo je moudrý, tak jako šípař [zbrojíř] hrot",
  "34": "jako ryba na zem vyvržená, ze svého vodního útulku vytažená, tak se zmítá tato mysl, Márovo panství má-li opustit",
  "35": "těžko udržitelnou a hbitou která podle libosti poletuje : tuto mysl zkrotit je dobré, zkrocená mysl přináší blaženost",
  "36": "velmi těžko viditelnou a velmi jemnou která podle libosti poletuje : tuto mysl hlídat by měl moudrý, střežená mysl přináší blaženost",
  "37": "v dálkách se osaměle toulající nehmotnou a v skrytu sídlící : tuto mysl kdo ukázní, osvobodí se z Márových pout",
  "38": "kdo nemá ustálenou mysl, pravou Dhammu nezná a má chatrnou důvěru, moudrosti naplnění nedojde",
  "39": "kdo nemá chtíčem naplněnou mysl a nemá útočnou vůli kdo dobro i zlo opustil : pro toho, bdělého, již není strachu",
  "40": "jako hliněný džbán že je toto tělo, nahlédnouce, jako pevnost tuto mysl opevněte, zaútočte na Máru se zbraní moudrosti a ochraňujte bez odpočinutí, co kdo dobude",
  "41": "zakrátko bude toto tělo na zemi ležet, opuštěné a bez vědomí jako neužitečný kus dřeva",
  "42": "cokoli si nepřátelé mohou navzájem způsobit, nebo ti, co se vzájemně nenávidí, špatně vedená mysl ještě horší věci ti způsobí",
  "43": "co ti matka ani otec nemohou způsobit, ani žádný jiný příbuznýsprávně vedená mysl ještě lepší věci ti způsobí",
  "chap4": "Květiny",
  "44": "kdo tuto zemi pronikne a tento svět smrti s jeho bohy ? kdo tato slova Dhammy dobře vyložená jako odborník květinu vycítí ?",
  "45": "ten, kdo se cvičí, tuto zemi pronikne a tento svět smrti s jeho bohy, ten, kdo se cvičí, tato slova Dhammy dobře vyložená jako odborník květinu vycítí",
  "46": "jako pěna je toto tělonahlédnuv, jeho povahu přeludu dokonale pochopiv, odetni Márovy květiny [rozkoší] a tam, kde tě nespatří král smrti, odejdi",
  "47": "kdo jen květiny [rozkoší] sbírá, člověk s ulpívající myslí, jako na spící vesnici velká povodeň, tak na něj přijde a uchvátí ho smrt",
  "48": "kdo jen květiny [rozkoší] sbírá, člověk s ulpívající myslí, nenasytný ve smyslných požitcích, toho se zmocní ukončitel životů",
  "49": "jako včela z květiny, aniž by její barvě a vůni uškodila, sesbírá nektar a odletí, tak nechť mudrc prochází vesnicí",
  "50": "ne na ostatních přestupky, ne na to, co ostatní vykonali nebo nevykonali, ale sám na sebe se ohlížej, co jsi vykonal nebo nevykonal",
  "51": "jako nádherná květina, krásně zbarvená, ale bez vůně, taková je dobře vyslovená řeč, neplodná je pro toho, kdo podle ní nejedná",
  "52": "jako nádherná květina, krásně zbarvená a vonící, taková je dobře vyslovená řeč, plodná je pro toho, kdo podle ní jedná",
  "53": "jako z hromady květin lze vytvořit věnců mnoho, tak ze zrození smrtelníka vykonáno by mělo být prospěšného mnoho",
  "54": "vůně květin nejde proti větru, ani vůně santalu, tagary či jasmínu, ale vůně dobrých jedinců pronikne i proti větru, jejich vůně vane všemi směry",
  "55": "ať santal, tagara, lotos či jasmín, mezi těmito vůněmi vůně ctnosti je nepřekonatelná",
  "56": "chabá je tato vůně tagary či santalu, avšak vůně ctnostných, která vane až k bohům, je nejvyšší",
  "57": "k těm, kdo jsou obdařeni ctností, prodlévají v dbalosti a jsou osvobozeni správným poznáním, Mára nenajde stezku",
  "58": "jako z hromady smetí vyhozené u silnice může vyrůst lotos, krásně vonící a mysl potěšující,",
  "59": "tak v davu bytostí, zaslepených obyčejných světských lidí, vyzařuje moudrost žák dokonale Probuzeného",
  "chap5": "Pošetilý",
  "60": "dlouhá je bdícímu noc, dlouhá je míle znavenému, dlouhý je koloběh životů pošetilcům, neznalým dobrého učení",
  "61": "jestliže v životě nenajdeš někoho lepšího nebo sobě rovného, pak vytrvale žij sám, není pro tebe sdružování s pošetilými",
  "62": "'ach moji synové, ach můj majetek' tak se trápí pošetilý, jenž ani sám sobě nepatří, natož synové, natož majetek",
  "63": "pošetilý, jenž se považuje za pošetilého, moudrým se stane, ale pošetilý, který se má za moudrého, vpravdě pošetilým je nazýván",
  "64": "i když po celý život pošetilý s moudrým pobývá, nepozná Dhammu, tak jako lžíce neokusí chuť polévky",
  "65": "i když pouhý okamžik vnímavý [inteligentní] člověk s moudrým pobývá, rychle pozná Dhammu, tak jako jazyk okouší chuť polévky",
  "66": "pošetilí a hloupí se chovají sami k sobě jako nepřátelé, tím, že konají zlé činy, které nesou trpké plody",
  "67": "takový čin nebyl vykonán dobře, kterého po vykonání lituješ, jehož se slzami v tváři a s nářkem následek pak sklízíš",
  "68": "takový čin byl vykonán dobře, kterého po vykonání nelituješ, jehož s potěšením a radostí následek pak sklízíš",
  "69": "za med ho může považovat pošetilec, zlo, dokud nedozraje, když však zlo dozraje, pak stihne pošetilce strast",
  "70": "stéblem trávy měsíc za měsícem může pošetilec pojídat své jídlo, těch, kdo pochopili Dhammu, tím však nedosáhne ani šestnáctinu jejich ceny",
  "71": "ani vykonaný zlý čin se ihned, tak jako mléko, nesrazí, ale doutnaje, následuje pošetilce jako oheň skrytý v žhavých uhlících",
  "72": "pouze k vlastnímu neprospěchu bude pošetilci popularita [věhlas], zničí pošetilci pravé štěstí a rozláme mu hlavu",
  "73": "přeje si nezasloužené postavení, přednost mezi mnichy, představenství v klášteře a pocty od laických rodin",
  "74": "'nechť si o mě myslí hospodáři i ti, co odešli do bezdomoví, že toto jsem udělal já sám, nechť sám rozhoduji co má být konáno a co ne'takové jsou pošetilcovy myšlenky [záměry] a jeho žádosti a domýšlivost jen vzrůstají",
  "75": "jiné je získávání materiální opory, jiné je to, co vede k odpoutání [vyhasnutí], toto pochopiv, mnich, který je žákem probuzeného by si neměl libovat v poctách a zachovávat si od nich odstup",
  "chap6": "Moudrý",
  "76": "jako toho, kdo ukazuje poklady nahlížej toho, kdo vidouc tvé chyby ti je vytknemoudrý, s tímto mudrcem pobývej, neboť pro takto pobývajícího je to lepší, nikoli horší",
  "77": "tím, že poučuje, radí a od nízkých způsobů odvrací, uvědomělým je milý, neuvědomělým je nemilý",
  "78": "nepobývej se špatnými přáteli, nepobývej s nízkými lidmi, pobývej s dobrými přáteli, pobývej se vznešenými lidmi",
  "79": "kdo je nadšený Dhammou dlí blaženě, s povznešenou myslí, ušlechtilými hlásanou Dhammou vždy je potěšen moudrý",
  "80": "vodu rozvádějí zavlažovači, šípaři obrábějí hroty, dřevo obrábějí tesaři, sebe ovládají moudří",
  "81": "jako skála z jednoho kusu není otřesena větrem, tak hanou či chválou nepohnuti jsou moudří",
  "82": "jako jezero, hluboké, zářivě čisté a nezčeřené, tak, vyslechnouce Dhammu, zářivě čistými se stanou moudří",
  "83": "kdekoli se nacházejí dobří jedinci, jsou zdrženliví, mírní netlachají pro potěšení, ať dotčeni štěstím či strastí, moudří nedají najevo povznesení či skleslost",
  "84": "ani kvůli sobě ani kvůli ostatním neměl by si člověk přát syna, bohatství či království, neměl by si přát získat vlastní prospěch nepravým způsobem, tak se stane ctnostným, moudrým a pravdivým",
  "85": "málo je mezi lidmi těch jedinců, kteří překročí na druhý břeh, ostatní lidé jen sem a tam po tomto [břehu] pobíhají",
  "86": "ti, kdo správně ukazují Dhammu a následují Dhammu, tito jedinci překročí tuto říši smrti, kterou je těžké překonat",
  "87": "temné učení když zavrhl a rozvíjí jasnéten, kdo je moudrý odešel z domova do bezdomoví a dlí v odloučení, z něhož je těžké se radovat",
  "88": "vyšší radost by si měl přátodvrhnuv smyslné požitkyten, kdo nic nemá, měl by se očistit od toho, co znečisťuje myslten, kdo je moudrý",
  "89": "ti, kdo členy probuzení správně ve své mysli rozvinuli, těší se ze zanechání, z neulpívání se radují, oproštěni od zákalů a plni jasu, již v tomto světě jsou zcela odpoutáni",
  "chap7": "Zasloužilý",
  "90": "u toho, kdo dokončil cestu a je prost trápení, osvobozeného ve všech směrech, jenž opustil všechna pouta, již nelze nalézt horečnatost",
  "91": "ti, kdo jsou obdařeni energií a uvědoměním se neradují ve svých obydlích, jako labutě odlétají z jezer, tak opouštějí své domovy",
  "92": "těch, kdo nic nehromadí, kdo porozuměli jídlu : prázdnota prostá znaků a osvobození je jejich pastvou, jako ptáků v prostoru je jejich cesta nepostižitelná",
  "93": "těch, jejichž zákaly jsou zcela odstraněny a jsou nezávislí na výživě : prázdnota prostá znaků a osvobození je jejich pastvou, jako ptáků v prostoru je jejich stopa [cesta] nepostižitelná",
  "94": "koho smysly došly uklidnění jako když vozataj dobře zvládne koně, kdo opustil domýšlivost a je bez zákalů, takového mají v lásce i bohové",
  "95": "kdo není vzdorovitý, podobně jako země, kdo je kultivovaný a je jako Indův sloup, kdo je jako nezkalené jezero, pro takového již neexistuje koloběh putování",
  "96": "mírná je jeho mysl, mírná je řeč i činy toho, kdo je osvobozen správným poznáním, kdo dospěl k míru a je takový",
  "97": "mimo pouhou důvěru, kdo [sám] poznal nestvořené, člověk, který odetnul svá pouta [spojení], ukončil své naděje a odvrhl své očekávání, ten je nejvyšším jedincem",
  "98": "ať ve vsi či v lese, v údolí či na pláni, kdekoliv prodlévají Zasloužilí, to jsou místa radosti",
  "99": "radostné jsou lesy, v nichž se běžní lidé neradují, ti, kdo jsou prosti vášně se v nich však radují, neboť nehledají smyslové požitky",
  "chap8": "Tisíc",
  "100": "než tisíc výroků z nesmyslných slov sestávajících, je jediné smysluplné slovo lepší, jehož vyslechnutí je utišující",
  "101": "než tisíc veršů z nesmyslných slov sestávajících, je jediné slovo verše lepší, jehož vyslechnutí je utišující",
  "102": "než recitovat sto veršů z nesmyslných slov sestávajících, je jediné slovo o Dhammě lepší, jehož vyslechnutí je utišující",
  "103": "i kdyby někdo tisíckrát nad tisíci muži v bitvě zvítězil, jedině ten, kdo zvítězil sám nad sebou je v bitvě vítězem nejvyšším",
  "104": "nad sebou zvítězit je lepší než nad jinými bytostmi, člověk, jenž zkrotil sám sebe se stále chová ukázněně",
  "105": "žádný bůh ani nebeská bytost ani Mára spolu s Brahmou ne-přemění v porážku vítězství takového člověka",
  "106": "měsíc po měsíci kdybys tisíc obětí přinášel po sto let a nebo jednou toho, kdo sám sebe rozvinul jen na okamžik uctil, toto uctění by bylo lepší než oněch sto let obětování",
  "107": "kdybys sto let života [obětní] oheň obcházel v lese a nebo jednou toho, kdo sám sebe rozvinul jen na okamžik uctil, toto uctění by bylo lepší než oněch sto let obětování",
  "108": "cokoliv nabídne či obětuje ve světě třeba po celý rok ten, kdo hledá zásluhy přinášením obětí, nedojde tím vším ani čtvrtiny [zásluh], lepší je prokázat úctu tomu, kdo je na přímé stezce",
  "109": "kdo pozdrav má ve zvyku a stále starší ctí čtyři věci u něj vzrůstají : dlouhý život, krása, štěstí a síla",
  "110": "než sto let života bez ctnosti a bez soustředění je lepší jeden den prožitý ctnostně a v meditačním pohroužení",
  "111": "než sto let života bez moudrosti a bez soustředění je lepší jeden den prožitý moudře a v meditačním pohroužení",
  "112": "než sto let života v lenosti a ochablosti je lepší jeden den prožitý energicky a upevněně",
  "113": "než sto let života bez vidění vzniku a zániku je lepší jeden den prožitý s viděním vzniku a zániku",
  "114": "než sto let života bez vidění bezsmrtného stavu je lepší jeden den prožitý s viděním bezsmrtného stavu",
  "115": "než sto let života bez vidění nejvyšší Dhammy je lepší jeden den prožitý s viděním nejvyšší Dhammy",
  "chap9": "Zlo",
  "116": "neváhej v konání dobra a odvracej mysl od zla, kdo váhá v konání dobra [zásluh] jeho mysl najde zalíbení ve zlu",
  "117": "vykonal-li člověk zlo, nechť ho již nevykonává znovu a znovu, nechť nemá vůli ho dále vykonávat, neboť nahromadění zla je utrpení",
  "118": "vykonal-li člověk dobro [zásluhy], nechť ho vykonává znovu a znovu, nechť má vůli ho dále vykonávat, neboť nahromadění dobra [zásluh] je štěstí",
  "119": "i zlý člověk zakouší dobro dokud jeho zlo neuzraje, když však jeho zlo uzraje, pak zlý člověk zakouší zlo",
  "120": "I dobrý člověk zakouší zlo dokud jeho dobro neuzraje, když však jeho dobro uzraje, pak dobrý člověk zakouší dobro",
  "121": "nepodceňujte zlé skutky : 'nic z toho se mi nevrátí', i kapky vody padající vodou džbán naplní, tak naplní se pošetilec zlem, když trošku po trošce ho nahromadí",
  "122": "nepodceňujte dobré skutky : 'nic z toho se mi nevrátí', i kapky vody padající vodou džbán naplní, tak naplní se moudrý dobrem, když trošku po trošce ho nahromadí",
  "123": "jako [se vyhne] obchodník nebezpečné cestě, má-li malou karavanu a velký majetek, nebo člověk milující život [se vyhne] jedu, tak je třeba vyhýbat se zlu",
  "124": "když ruka není poraněná, může tato ruka nést jed a jed do ní nemůže nasáknout a proniknout, tak zlo nemůže postihnout toho, kdo ho sám neprovádí",
  "125": "ublíží-li někdo nezkaženému člověku nebo čisté osobě bez poskvrny, vrátí se toto zlo pošetilci zpět jako jemný prach vržený proti větru",
  "126": "někteří se znovuzrodí v lůně, vykonavatelé zla [se znovuzrodí] v pekle, kdo správně postupují půjdou do nebe, kdo jsou prosti zákalů dosáhnou úplného odpoutání",
  "127": "ani v nebeském prostoru, ani uprostřed oceánu, ani když člověk odejde do horské jeskyně, v oblasti tohoto světa [vesmíru] nenajde místo, kde by mohl spočinout a uniknout svým zlým činům",
  "128": "ani v nebeském prostoru, ani uprostřed oceánu, ani když člověk odejde do horské jeskyně, v oblasti tohoto světa [vesmíru] nenajde místo, kde by mohl spočinout aniž by ho zkosila smrt",
  "chap10": "Hůl",
  "129": "všichni se třesou před holí [trestem], všichni se bojí smrti, přirovnávaje ostatní k sobě, nechť nikdo nezabíjí ani k tomu nenavádí",
  "130": "všichni se třesou před holí [trestem], všem je život milý přirovnávaje ostatní k sobě, nechť nikdo nezabíjí ani k tomu nenavádí",
  "131": "bytostem toužícím po štěstí kdo holí [zbraní] ubližuje, sám hledaje štěstí, po smrti nezíská štěstí",
  "132": "bytostem toužícím po štěstí kdo holí [zbraní] neubližuje, sám hledaje štěstí, po smrti získá štěstí",
  "133": "nehovoř hrubě k nikomu nebo ti stejnými slovy odpoví, vskutku strastná je vznětlivá řeč, tato hůl [zbraň] tě zpětně udeří",
  "134": "budeš-li sám ztichlý jako puklý gong, dosáhl jsi odpoutání [vyhasnutí] a vznětlivost již u tebe není k nalezení",
  "135": "jako pastýř holí dobytek vyhání na pastvu, tak stáří a smrt život vyhánějí z živých bytostí",
  "136": "když vykonává zlé činy, pošetilec nechápe co dělá, vlastními činy bude hlupák trýzněn, jakoby jej pálil oheň",
  "137": "kdo ozbrojený neozbrojeným nezkaženým bytostem ubližuje, do některé z těchto deseti situací rychle se dostane :",
  "138": "kruté a zničující pocity, tělesné zranění [rozpad], těžké onemocnění pomatenost mysli ho stihnou,",
  "139": "potíže u krále, strašné pomluvy, oddělení od příbuzných či pozbytí majetku",
  "140": "nebo jeho domy spálí plameny ohně či se po rozpadu těla takový nemoudrý člověk znovuzrodí v pekle",
  "141": "ani nahota, ani spletené vlasy, ani bláto, ani odmítání jídla, ani spaní na holé zemi, ani prach a špína, ani dřepění na patách ne-očistí smrtelníka, který nepřekonal své pochybnosti",
  "142": "kdo se třeba obléká zdobně, avšak má klidné chování, je mírný, zkrocený, má jistotu, vede čistý [svatý] život a vůči všem živým bytostem odložil hůl [zbraň], ten je vskutku bráhmanem, asketou, mnichem",
  "143": "člověk ovládaný studem špatně jednatkdo takový je k nalezení ve světě, kdo chápe, co je to hanba, [kdo je] jako ušlechtilý kůň [ovládaný] bičem ?",
  "144": "jako ušlechtilý kůň popohnaný bičem buďte horliví a obdaření pocitem naléhavosti, důvěrou, ctností a energií, soustředěním a zkoumáním Dhammy, obdařeni věděním, správným jednáním a uvědoměním opusťte toto nemalé utrpení",
  "145": "vodu rozvádějí zavlažovači šípaři obrábějí ostří dřevo obrábějí tesaři sami sebe ovládají [krotí] ti, kdo jednají správně",
  "chap11": "Stáří",
  "146": "jak se lze smát, jak se lze radovat, když toto vše je stále v plamenech, temnotou obklopeni nebudete hledat světlo ?",
  "147": "pohleď na tuto myslí vytvořenou loutku, navršenou hromadu neduhů a nemocí, naplněnou myšlenkami, v níž není nic trvalého a stálého",
  "148": "zkáze podléhá toto tělo, křehké hnízdo nemocí, rozpadá se v hnijící změť, když smrt ukončí jeho život",
  "149": "[zbudou-li] jen tyto rozházené, jako seschlé tykve vybělené kosti, lze se při takovém pohledu radovat [ze života] ?",
  "150": "z kostí je toto město postavené, masem a krví omítnuté, v něm stáří a smrt, domýšlivost a pohrdavost jsou ukryté",
  "151": "zestárnou i královy pestře zbarvené vozy, rovněž toto tělo dochází stárnutí, jen dobrá Dhamma stárnutí nedochází a mírní [ctnostní] ji dávají poznat dobrým lidem",
  "152": "[v Dhammě] nepoučený člověk stárne jako vůl, přibývá mu masa, ale moudrosti mu nepřibývá",
  "153": "nejedním zrozením v tomto koloběhu životů prošel jsem, nenalézaje, stavitele tohoto domu hledaje, strastné je zrozování opětovné",
  "154": "staviteli domu, nyní však jsi spatřen, znovu dům již nepostavíš, všechny krokve jsou zlámané, hřeben domu je roztříštěn, do nezformovaného stavu vstoupila mysl, toužení dospělo k ukončení",
  "155": "ti, kdo nežili čistým [svatým] životem a nezískali v mládí duchovní bohatství, chřadnou jako stará volavka u jezera bez ryb",
  "156": "ti, kdo nežili čistým [svatým] životem a nezískali v mládí duchovní bohatství, leží jako zlomené luky a oplakávají staré časy",
  "chap12": "O Sobě",
  "157": "kdo je sám sobě milý, nechť se opatruje, dobře opatruje, ve všech třech obdobích života nechť nad sebou bdí ten, kdo je moudrý",
  "158": "nejprve sám sebe ať ustaví v tom, co je správné, pak teprve nechť poučuje druhé, nechť se [porušováním toho] nepošpiňuje ten, kdo je moudrý",
  "159": "kdo sám v sobě vyvinul to, v čem poučuje druhé, ten je vskutku dobře zkrocený a zvládnutý, neboť sám sebe je vpravdě obtížné zvládnout",
  "160": "každý je vskutku sám sobě ochráncem, kdo jiný by mu mohl být ochráncem ? kdo sám sebe dobře zkrotí, získává onu ochranu, jež je těžko získatelná",
  "161": "zlo vykonané jím samým, zrozené z něj samého, vzešlé z něj samého, rozdrtí hloupého člověka, tak jako diamant [rozdrtí] drahokam",
  "162": "ten, kdo je nadmíru nectnostný, jako když popínavá rostlina dusí sálový strom, tak se chová sám k sobě, jak by mu to přál jen jeho nepřítel",
  "163": "je snadné konat věci nedobré a sobě samému neprospěšné, ale co je vpravdě prospěšné a dobré, to je vpravdě nanejvýš obtížné konat",
  "164": "když učením zasloužilých, ušlechtilých jedinců, kteří žijí podle Dhammy, hloupý člověk pohrdá, opíraje se o zlé názory, tak jako plody bambusu, přinese mu to plody sebezničení",
  "165": "kdo sám koná zlo, sám sebe znečišťuje, kdo sám nekoná zlo, sám sebe očišťuje, čistým nebo nečistým se každý sám učiní, nikdo někoho jiného očistit ne-může",
  "166": "svůj vlastní cíl kvůli cílům druhých, jakkoli velkým, neztrácej, kdo přímo poznal svůj vlastní cíl, nechť se zaměří právě na něj",
  "chap13": "Svět",
  "167": "nepraktikuj nízké věci, nežij nedbale, nepraktikuj špatné názory a nerozvíjej světskost",
  "168": "vzchop se a buď dbalý, žij správně podle Dhammy, kdo žije podle Dhammy spočívá šťastně, na tomto i na onom světě",
  "169": "žij správně podle Dhammy, nežij nesprávně, kdo žije podle Dhammy spočívá šťastně, na tomto i na onom světě",
  "170": "nazírej ho jako bublinu, nazírej ho jako přelud, kdo takto nahlíží tento svět, toho král smrti nespatří",
  "171": "pojď a pohleď na tento svět, ozdobený jako královský kočár, kde pošetilí jsou ponořeni, nejsou upoutáni vědoucí",
  "172": "kdo byl dříve nedbalý, ale později se stal dbalým, ozáří tento svět jako z mraků vynořivší se měsíc",
  "173": "kdo konal zlé činy, ale pak prospěšnými je odčinil, ozáří tento svět jako z mraků vynořivší se měsíc",
  "174": "oslepený je tento svět, jen málokdo je tu jasně vidoucí, jako pták, jenž se vyprostil ze sítě, málokdo do nebeských světů odejde",
  "175": "labutě létají cestou za sluncem, ti, kdo mají magické síly létají prostorem, moudří však odlétají z tohoto světa, když přemohli Máru s jeho armádou",
  "176": "této jedné věci nechávaje průchod, člověk, který vědomě lže, nedbaje onoho světa [po smrti], není pro něj zla, které by nevykonal",
  "177": "lakomci se do světa bohů ne-dostanou, jelikož tito pošetilci neoceňují štědrost, moudří se však ze štědrosti radují, a tak budou šťastní na onom světě [po smrti]",
  "178": "než svrchovaně vládnout celé Zemi, než vstoupit do nebeského světa, než panovat celému světu [vesmíru], plody vstupu do proudu [Dhammy] jsou lepší [větší]",
  "chap14": "Probuzený",
  "179": "jeho vítězství nemůže být překonáno, jeho vítězství nemůže obsáhnout nikdo ve světě, Probuzeného pastvou je nekonečnost, jakým způsobem bys ho mohl svést z cesty ?",
  "180": "jeho lepivá spleť toužení již nikdy nemůže svést, Probuzeného pastvou je nekonečnost, jakým způsobem bys ho mohl svést z cesty ?",
  "181": "moudří, kteří se věnují meditačnímu pohroužení a těší se z klidu odříkání, i bohům jsou drazí, zcela probuzení a uvědomělí",
  "182": "těžko lze získat lidské zrození, těžký je život smrtelníků, těžké je [mít možnost] vyslechnout pravou Dhammu, těžko je [možné zažít] vyvstání Probuzených",
  "183": "nekonání žádného zla, provádění toho, co je prospěšné, očišťování své mysli, to je učení Probuzených",
  "184": "vytrvalá trpělivost je nejvyšší askezí, odpoutání je to nejvyšší, říkají Probuzení, není poutníkem ten, kdo škodí druhým, není asketou ten, kdo ubližuje druhým",
  "185": "nemluvit urážlivě a neškodit, ovládat se podle pravidel cvičení, být střídmý v jídle, prodlévat v samotě a oddávat se vyšší mysli, to je učení Probuzených",
  "186": "ani deštěm zlaťáků ne-lze dosáhnout ukojení smyslových požitků, neradostné a strastné jsou smyslové požitky, to poznal moudrý",
  "187": "ani v nebeských smyslových požitcích potěšení nenalézá ten, jehož potěšením je odstranění toužení : žák dokonale Probuzeného",
  "188": "mnozí útočiště hledají v horách či v lesích, v zahradách či stromových svatyních : lidé strachem vyděšení",
  "189": "to však nejsou útočiště bezpečná, to nejsou útočiště nejvyšší, ne ten, kdo k těmto útočištím jde, od veškeré strasti se osvobodí",
  "190": "kdo však k Buddhovi, k Dhammě a k Sangze jako ke svému útočišti jde a čtyři ušlechtilé pravdy se správným porozuměním vidí :",
  "191": "strast, vznikání strasti, strasti překonání a ušlechtilou osmičlennou stezku k utišení strasti vedoucí :",
  "192": "to jsou útočiště bezpečná, to jsou útočiště nejvyšší, kdo k těmto útočištím jde, od veškeré strasti se osvobodí",
  "193": "je obtížné nalézt jedince obdařeného poznáním, neboť se všude nerodí, kde se takový mudrc zrodí, té rodině se šťastně daří",
  "194": "šťastné je vyvstání Probuzených, šťastné je vykládání pravé Dhammy, šťastný je soulad Sanghy, šťastná je askeze těch, kdo jsou v souladu",
  "195": "uctí-li někdo ty, kdo jsou úcty hodní, Probuzené nebo jejich žáky, kteří překonali mentální rozbujelost a překročili trápení a naříkání,",
  "196": "uctí-li ty, kdo jsou takoví, odpoutaní a oproštění od strachu, je nemožné spočítat jeho zásluhy, které jsou nezměrné",
  "chap15": "Štěstí",
  "197": "velmi šťastně žijeme mezi nenávistnými bez nenávisti [zášti], mezi nenávistnými lidmi prodléváme bez nenávisti",
  "198": "velmi šťastně žijeme mezi nemocnými bez nemocí, mezi nemocnými lidmi prodléváme bez nemocí",
  "199": "velmi šťastně žijeme mezi vzrušenými nevzrušeně, mezi vzrušenými lidmi prodléváme nevzrušeně",
  "200": "velmi šťastně žijeme my, kdo nic nemáme, budeme se živit radostným nadšením jako Zářící bohové",
  "201": "vítězství plodí nenávist [zášť], poražený žije strastně, ten, kdo dosáhl míru, žije šťastně, neboť odložil stranou vítězství i porážku",
  "202": "není ohně, jež by se vyrovnal vášni, není hříchu, jež by se vyrovnal nenávisti, není utrpení, jež by se vyrovnalo osobnostním skupinám, není většího štěstí než je stav míru",
  "203": "nenasytnost je největší nemocí, formace jsou největším utrpením, pro toho, kdo toto poznal v souladu se skutečností, je odpoutání [vyhasnutí] největším štěstím",
  "204": "[mentální] zdraví je největším ziskem, spokojenost je největším bohatstvím, důvěra [v Učení] je největším přítelem, odpoutání [vyhasnutí] je největším štěstím",
  "205": "kdo okusil chuť samoty a chuť klidu, oproštěn od bídy a zla, zakouší chuť nadšení z Dhammy",
  "206": "je dobré vídat ušlechtilé, pobývání s nimi je vždy šťastné, kdo nemusí vídat pošetilé, může být stále šťastný",
  "207": "kdo s pošetilci se stýká, dlouhou dobu se trápí, strastná je pošetilců společnost jako nepřátelůvždy, moudrých však šťastná je společnost jako s příbuznými setkání",
  "208": "proto [následujte] moudrého, rozumného a dobře poučeného, vytrvalého v ctnosti a ušlechtilého, dbalého svých povinností, takového moudrého člověka následujte, jako měsíc svou dráhu skrze souhvězdí",
  "chap16": "O Tom, co je Milé",
  "209": "kdo se oddává věcem, kterým by se neměl oddávat a neoddává se věcem, kterým by se měl oddávat, kdo opustí pravý cíl kvůli tomu, co je mu milé, bude závidět těm, kdo se oddávají svému cíli",
  "210": "nespojuj se s tím, co je milé ani s tím, co je nemilé, je utrpení nevidět to, co je milé a vidět to, co je nemilé",
  "211": "proto nechovej nic jako milé, neboť je zlé ztratit něco milého, u toho již pouta nejsou k nalezení, komu není nic milé ani nemilé",
  "212": "z toho, co je milé se rodí trápení, z toho, co je milé se rodí strach, kdo se oprostil od toho, co je milé, pro toho není trápení, natož strachu",
  "213": "z toho, co je drahé se rodí trápení, z toho, co je drahé se rodí strach, kdo se oprostil od toho, co je drahé, pro toho není trápení, natož strachu",
  "214": "z potěšení se rodí trápení, z potěšení se rodí strach, kdo se oprostil od potěšení, pro toho není trápení, natož strachu",
  "215": "ze smyslových požitků se rodí trápení, ze smyslových požitků se rodí strach, kdo se oprostil od smyslových požitků, pro toho není trápení, natož strachu",
  "216": "z toužení se rodí trápení, z toužení se rodí strach, kdo se oprostil od toužení, pro toho není trápení, natož strachu",
  "217": "kdo je obdařen ctností a viděním, je spravedlivý a zná pravdu, kdo splnil svůj úkol, ten je lidem milý",
  "218": "v kom se zrodila touha po tom, co nelze popsat a dotkl se toho svou myslí, koho mysl není spoutána smyslovými požitky, o tom se říká, že pluje proti proudu",
  "219": "když se člověk po dlouhé nepřítomnosti šťastně vrátí z daleka domů, jeho příbuzní, přátelé a druhové se radují z jeho návratu",
  "220": "podobně toho, kdo konal záslužné skutky, když odejde z tohoto světa na onen svět, záslužné skutky ho uvítají, jako milého příbuzného, jenž se vrátil domů",
  "chap17": "Hněv",
  "221": "zanech hněvu, úplně opusť domýšlivost, a překonej všechna pouta, kdo nelpí na jménu-a-hmotě, toho nepostihne žádná strast",
  "222": "kdo vzmáhající se hněv jako odbržděný povoz zastaví, toho nazývám vozatajem, ostatní jen drží otěže",
  "223": "bezhněvností překonej hněv, nedobré dobrotou překonej, překonej lakomce štědrostí a pravdou lháře",
  "224": "mluv pravdu a nepodlehni zlobě, požádán daruj i z mála, skrze tyto tři věci dojdeš do společnosti bohů",
  "225": "mudrci, kteří zanechali ubližování a stále ovládají své tělo, dosáhnou neochvějného stavu, kde dojdou oproštění od trápení",
  "226": "ti, kdo jsou vždy bdělí a cvičí se dnem i nocí, zaměřeni k odpoutání, dojdou k ukončení zákalů",
  "227": "i v dávných dobách, Atulo, nejen dnes, byli haněni ti, kdo nemluví, byli haněni ti, kdo mluví mnoho i ti, kdo mluví přiměřeně byli haněni, není ve světě ten, kdo není haněn",
  "228": "nebyl a nebude ani nyní není k nalezení ten, kdo by byl pouze haněn nebo pouze chválen",
  "229": "ale ti, kdo jsou inteligentní pochválí toho, u koho den za dnem pozorují, že jeho jednání je bez poskvrny a je moudrý, obdařený porozuměním, ctností a soustředěním",
  "230": "kdo je jako zlatý šperk, jak by si mohl zasloužit hanu, i bohové ho chválí, ba i Brahmou je chválen",
  "231": "chraň se tělesného jednání v hněvu, buď vládcem svého těla, zanech špatného jednání tělem a praktikuj správné jednání tělem",
  "232": "chraň se mluvení v hněvu, buď vládcem své řeči, zanech špatného jednání řečí a praktikuj správné jednání řečí",
  "233": "chraň se myšlení v hněvu, buď vládcem svého myšlení, zanech špatného jednání myslí a praktikuj správné jednání myslí",
  "234": "mudrci, kteří ovládají své tělo, kteří ovládají svou řeč, mudrci, kteří ovládají svou mysl, ti se zcela a dokonale ovládají",
  "chap18": "Poskvrna",
  "235": "jsi nyní jako zežloutlý list, poslové smrti tě již očekávají, stojíš u výchozí brány a nemáš nic co by sis vzal na cestu",
  "236": "proto si v sobě vytvoř ostrov a rychle usiluj aby ses stal moudrým, zbavíš-li se poskvrn a nečistot, přijdeš do nebeské říše ušlechtilých",
  "237": "jsi nyní u konce života, dospěl jsi do blízkosti smrti, není už pro tebe spočinutí a nemáš nic co by sis vzal na cestu",
  "238": "proto si v sobě vytvoř ostrov a rychle usiluj aby ses stal moudrým, zbavíš-li se poskvrn a nečistot, nepůjdeš znovu vstříc zrození a stárnutí",
  "239": "nechť se moudrý postupně, trošku po trošce, kousek po kousku tak jako zlatník stříbro, zbavuje poskvrn",
  "240": "jako rezavá skvrna vzniklá ze železa, sama toto železo stravuje, tak toho, kdo žije zhýrale jeho vlastní činy přivedou do bědných stavů",
  "241": "nerecitování je poskvrnou ústní tradice, netečnost je poskvrnou domácnosti, poskvrnou krásy je lenost, nedbalost je poskvrnou ochránce",
  "242": "ženu poskvrňuje špatné chování, chamtivost je poskvrnou dárce, zlé věci jsou poskvrnou na tomto i na onom světě",
  "243": "avšak je ještě větší poskvrna než tyto poskvrny, nevědomost je největší poskvrnou, této poskvrny se zbavte a budete bez poskvrny, mniši",
  "244": "snadný život má nestoudník, který je chytrý jako vrána, pomlouvá druhé, je úskočný a drzý [nadutý] a jeho živobytí je pošpiněné",
  "245": "ten, kdo zná stud má však těžký život, kdo stále hledá jen čistotu, není líný ani drzý [nadutý], jeho živobytí je čisté a je prozíravý",
  "246": "když zabíjí živé bytosti, mluví lži, bere ve světě to, co mu nebylo darováno, chodí za ženou druhého",
  "247": "a požívání opojných nápojů když se člověk oddává, již zde, v tomto světě, si vykopává svůj vlastní kořen",
  "248": "toto milý člověče poznej : zlé stavy postihnou neukázněného, proto nedopusť aby tě chtivost a špatnost na dlouhou dobu stáhly do utrpení",
  "249": "podle své víry dávají lidé, podle své důvěry, kdo by se zde rmoutil kvůli jídlu a pití, jež dostali ostatní, ani ve dne, ani v noci, soustředění ne-dosáhne",
  "250": "kdo však takové [myšlenky] vymýtil, vykořenil a zcela zavrhl, ať ve dne či v noci, soustředění dosáhne",
  "251": "není ohně, jež by se vyrovnal vášni, není posedlosti, jež by se vyrovnala nenávisti, není sítě [pasti], jež by se vyrovnala zaslepenosti, není proudu, jež by se vyrovnal toužení",
  "252": "snadné je vidět chyby druhých, vlastní však těžké je vidět, druhých chyby jsou probírány jako plevy, vlastní však skrývány, jako svůj hřích zapírá podvodník",
  "253": "kdo vidí jen chyby druhých a neustále vnímá jejich provinění, u toho zákaly jen narůstají, je vzdálen odstranění zákalů",
  "254": "[pravá] cesta není v prostoru, [pravý] asketa není vně [nejeví se navenek], lidé si libují v mentální rozbujelosti, Tathágatové jsou však prosti mentální rozbujelosti",
  "255": "[pravá] cesta není v prostoru, [pravý] asketa není vně [nejeví se navenek], [mentální] formace nejsou věčné, v Probuzených není rozrušenost",
  "chap19": "Spravedlnost",
  "256": "není spravedlivý ten, kdo správnost neuváženě posuzuje, co je správné a co je nesprávnéobojí by měl moudrý rozvážit",
  "257": "kdo uváženě, podle Dhammy a nestranně vede druhé, ten je ochráncem Dhammy a [pravým] mudrcem, ten je nazýván 'spravedlivý'",
  "258": "není moudrým ten, kdo toho mnoho namluví, kdo zajišťuje bezpečí, kdo je prost zášti a prost strachu, ten je nazýván 'moudrý'",
  "259": "není držitelem Dhammy ten, kdo toho mnoho namluví, kdo však třeba jen málo vyslechl, Dhammu však svým tělem uzřel, ten je držitelem Dhammy, ten není nedbalý Dhammy",
  "260": "není Thérou [Starším] ten, kdo má jen zšedlé vlasy na hlavě, někdo může být pokročilého věku, a [přesto] je nazýván 'starý hlupák'",
  "261": "kdo je však naplněn pravdou a Dhammou, je nenásilný, ukázněný a zkrocený, ten je mudrcem bez poskvrny, ten je nazýván 'Théra'",
  "262": "ani ozdobná mluva, ani půvabný vzhled ne-dělají dobrého člověka, je-li závistivý, chamtivý a falešný",
  "263": "kdo však takové [vlastnosti] vymýtil, vykořenil a zcela zavrhl, ten je mudrcem, jenž zanechal nenávisti, ten je nazýván 'dobrý člověk'",
  "264": "kdo má jen oholenou hlavu není asketou, nedbá-li etických zásad a mluví falešně, kdo je obdařen žádostmi a chtivostí, jak by mohl být asketou ?",
  "265": "kdo však v sobě utišil zlé vlastnosti, ať malé či velké, všechny zlé vlastnosti kdo utišil, ten je nazýván 'asketa'",
  "266": "není mnichem ten, kdo jen žije z almužních darů ostatních, kdo praktikuje odporné věci, ten vůbec není mnichem",
  "267": "kdo se však nad dobro i zlo povznesl čistým životem a kráčí světem s rozvahou, ten je nazýván 'mnich'",
  "268": "ten, kdo jen mlčí není mudrcem je-li pošetilý a nevědoucí, kdo však jako na vahách považuje a vybírá to nejlepší, ten je moudrý",
  "269": "kdo se vyvaruje zlých činů, ten je mudrcem, proto je mudrcem, kdo zná oba světy, ten je nazýván 'mudrc'",
  "270": "není ušlechtilým ten, kdo živým bytostem ubližuje, kdo neubližuje žádným živým bytostem, ten je nazýván 'ušlechtilý'",
  "271": "ne[mysli si], že když jsi dbal etických zásad a mnoho studoval či získal soustředění nebo pobýval v odloučení :",
  "272": "'dospěl jsem k blaženosti odříkání, kterou neprožívají obyčejní světští lidé'tuto důvěru v sobě ne-chovej, mnichu, dokud jsi nedosáhl odstranění zákalů",
  "chap20": "Stezka",
  "273": "ze stezek osmičlenná je nejlepší, z pravd čtyři pravdy, bezvášnivost je nejlepší z věcí [ze stavů], z dvounohých bytostí ten, kdo je vidoucí",
  "274": "jen toto je stezka a není jiné k očištění vidění, po ní postupujte a Máru oslepíte",
  "275": "budete-li po ní postupovat, učiníte konec strasti, ukazuji tuto stezku, když jsem konečně poznal, jak vytrhnout šíp [strasti]",
  "276": "vy sami musíte vyvinout horlivost, pouze ukazatelé cesty jsou Tathágatové, ti, kdo postupují po stezce se osvobodídlící v meditačním pohrouženíz Márových pout",
  "277": "všechny formace jsou nestálé, když to někdo moudře nahlédne, tak se odvrátí od utrpení, to je stezka k očištění",
  "278": "všechny formace jsou strastné, když to někdo moudře nahlédne, tak se odvrátí od utrpení, to je stezka k očištění",
  "279": "všechny věci [stavy] jsou ne-já, když to někdo moudře nahlédne, tak se odvrátí od utrpení, to je stezka k očištění",
  "280": "kdo neusiluje, když je čas k úsilí, jsa mladý a silný se oddává letargii, místo aby byl rozhodné mysli, jsa líný a letargický, stezku moudrosti nenalezne",
  "281": "kdo hlídá svou řeč a dobře ovládá svou mysl, nechť ani tělesně neprospěšný čin nevykoná, nechť tyto tři cesty činu očistí a vzbudí v sobě stezku, hlásanou zřeci",
  "282": "z oddanosti se rodí vědění, bez oddanosti vědění zaniká, tyto dvě cesty pochopivrozvoj a úpadek, měl by se člověk zařídit tak, aby jeho vědění vzrůstalo",
  "283": "celý les [žádostí] pokácejte, nejen nějaký strom, z tohoto lesa se rodí strach, když vymýtíte celý les i s podrostem, budete, mniši, odpoutaní [vyhaslí]",
  "284": "dokud není vymýcen i podrost [žádostí]byť nepatrnýmuže po ženě, jeho mysl je k ní připoutaná jako mléko sající tele ke své matce",
  "285": "vymyť sebelásku, jako bys na podzim vytrhl lilii, rozviň tuto stezku k míru a k odpoutání [vyhasnutí], kterou vykládá Blažený",
  "286": "'zde strávím dobu dešťů, zde zimu, zde léto'tak uvažuje pošetilec, který nechápe nebezpečí",
  "287": "kdo je opojen svými potomky a majetkem, člověk s ulpívající myslí, jako na spící vesnici velká povodeň, tak na něj přijde a uchvátí ho smrt",
  "288": "ani synové nejsou ochranou, ani otec či jiní blízcí, koho uchopí ukončitel životů, nemá již ochrany u příbuzných",
  "289": "pochopiv tento určující smysl, moudrý a ctností střežený člověk, stezku vedoucí k odpoutání [vyhasnutí] nechť rychle očistí",
  "chap21": "Různé",
  "290": "je-li možné opuštěním omezeného štěstí spatřit rozsáhlé štěstí, pak moudrý opustí omezené štěstí aby spatřil rozsáhlé štěstí",
  "291": "kdo způsobuje ostatním utrpení, v touze po vlastním štěstí, zaplete se do spleti nenávisti a z této nenávisti [zášti] se nevyprostí",
  "292": "ti, kdo odmítají to, co by měli dělat a dělají to, co by neměli dělatdrzí a nedbalíu těch zákaly jen narůstají",
  "293": "ale ti, kdo jsou správně upevnění, stále si uvědomují tělo, neprovádějí to, co by neměli a vytrvale konají to, co by měli, uvědomělí a jasně chápajícíti dojdou k ukončení zákalů",
  "294": "když zabil matku [žádostivost] a otce [klam 'já'], dva bojovné krále [víru ve věčnou existenci a víru v úplný zánik], a zničil království a jeho poddané [šest smyslových základen a vášeň], putuje bráhman prost strázně",
  "295": "když zabil matku [žádostivost] a otce [klam 'já'], dva učené krále [víru ve věčnou existenci a víru v úplný zánik], když zabil pětici tygrů [pět mentálních překážek], putuje bráhman prost strázně",
  "296": "jsou probuzení, zcela probuzenívždyGótamovi žáci, kteří si dnem i nocí stále uvědomují [připomínají] Buddhu",
  "297": "jsou probuzení, zcela probuzenívždyGótamovi žáci, kteří si dnem i nocí stále uvědomují Dhammu",
  "298": "jsou probuzení, zcela probuzenívždyGótamovi žáci, kteří si dnem i nocí stále uvědomují Sanghu",
  "299": "jsou probuzení, zcela probuzenívždyGótamovi žáci, kteří si dnem i nocí stále uvědomují tělo",
  "300": "jsou probuzení, zcela probuzenívždyGótamovi žáci, kteří dnem i nocí těší svou mysl neubližováním",
  "301": "jsou probuzení, zcela probuzenívždyGótamovi žáci, kteří dnem i nocí těší svou mysl [meditačním] rozvíjením",
  "302": "je těžké odejít do bezdomoví a nalézt v tom uspokojení, těžký a strastný je život hospodáře, strastné je pobývání mezi cizími lidmi, poutník [životy] je stále stíhán strastmi, proto nebuďte jen poutníky [životy], nedejte se stále stíhat strastmi",
  "303": "kdo je obdařen důvěrou a ctností, dosáhne slávy a bohatství, kamkoli přijde, tam bude poctěn",
  "304": "kdo je naplněný mírem, šíří jas již z dálky, jako zasněžený vrcholek, nemírný [nectnostný] však není zřetelný ani z blízka, jako šíp vystřelený v noci",
  "305": "kdo sám usedá a sám uléhá, sám se prochází a není pohodlný [líný], kdo sám sebe krotí [ovládá], bude spokojený v lesích",
  "chap22": "Peklo",
  "306": "ti, kdo říkají nepravdu [lžou] odcházejí do pekla, stejně jako ti, kdo něco udělají a říkají: 'neudělal jsem to' [zapírají], oba si po smrti budou rovnina onom světětito lidé nízkého konání",
  "307": "mnozí z těch, kdo se oděli oranžovým rouchem mají zlou povahu a jsou neukáznění, tito zlí se díky svým zlým činům znovuzrodí v pekle",
  "308": "lepší je spolknout železnou kouli, rozžhavenou jako planoucí oheň, než takto pojídat nectnostně a neukázněně almužní jídlo kraje",
  "309": "do čtyř stavů nedbalý muž, který svádí ženu druhého upadne: nahromadění viny [hříchu], neklidný spánek, zatřetí hanlivá pověst a začtvrté peklo",
  "310": "kromě nahromadění viny [hříchu] a zlého budoucího stavu jsou oba vystrašení i během krátké doby potěšení, neboť i král za to uvaluje těžký trest, proto by muž neměl svádět ženu druhého",
  "311": "jako ostrá tráva, je-li špatně uchopena, tu ruku pořeže, tak i špatně pojímaný asketický život tě svrhne do pekla",
  "312": "nějaký ledabyle vykonaný čin, nějaký nečistý zvyk nebo pochybně vedený svatý život nepřinese velké plody",
  "313": "co je třeba vykonat, to konejte upevněně a usilovně, neboť ledabylý odchod do bezdomoví zvedá nejvíce prachu",
  "314": "je lepší nevykonat špatný čin, neboť špatný čin [tě] poté spálí, lepší je vykonat dobrý čin, neboť ten [tě] nespálí",
  "315": "jako město na hranici země je střeženo uvnitř i zvenku, tak i vy střežte sami sebe, ani okamžik nepropásněte, ti, kdo na okamžik poleví, se pak trápí, když do pekla se dostanou",
  "316": "ti, kdo se hanbí za to, co hanebné není a nehanbí se za to, co hanebné je, přijímají špatné názory, tyto bytosti kráčí do bědných stavů",
  "317": "ti, kdo vidí nebezpečí v tom, co nebezpečné není a nevidí nebezpečí v tom, co nebezpečné je, přijímají špatné názory, tyto bytosti kráčí do bědných stavů",
  "318": "ti, kdo vidí chybu v tom, co chybou není a nevidí chybu v tom, co chybou je, přijímají špatné názory, tyto bytosti kráčí do bědných stavů",
  "319": "avšak ti, kdo rozpoznají chybu jakožto chybu a bezchybnost jakožto bezchybnost, přijímají správné názory, tyto bytosti kráčí do šťastných stavů",
  "chap23": "Nága",
  "320": "tak jako slon v bitvě z luku vystřelený šípje třeba snášet urážky, neboť mnoho lidí je nectnostných",
  "321": "zkrocený [slon] je voděn i ve shromáždění, na zkroceného [slona] usedne i král, i mezi lidmi je nejlepší ten, kdo je zkrocený, kdo umí snášet urážky",
  "322": "je skvělé [umět] zkrotit muly, ušlechtilé sindhské koně či statné velké slony, skvělejší je však [umět] zkrotit sám sebe",
  "323": "neboť nelze na žádném z těchto prostředků dojít do onoho kraje, kam noha nevkročí, kam jen ten, kdo sám sebe dobře zkrotil, skrze své zkrocení dojde",
  "324": "Dhanapálako, slona, který je v době říje, je těžké udržet, je-li upoután, nepožije ani sousta, vzpomíná na sloní les a na slony",
  "325": "kdo je malátný, přejídá se a ospale se povaluje jako velký vepř na krmníkutakový tupec vstupuje do lůna znovu a znovu",
  "326": "dříve se tato toulavá mysl zatoulala kamkoli se jí zachtělo, kdekoli jí bylo libo a příjemno, ode dneška ji však budu důkladně držet na uzdě, tak jako chomout drží slona v říji",
  "327": "radujte se z dbalosti, a dobře chraňte svou mysl, pozvedněte se z blátivé cesty jako slon z bahna do něhož zapadl",
  "328": "jestliže získáš bystrého přítele, souputníka, který má dobré chování a je prozíravý, pak, překonávaje všechna nebezpečí, putuj s ním, s potěšenou a uvědomělou myslí",
  "329": "jestliže nezískáš bystrého přítele, souputníka, který má dobré chování a je prozíravý, pak, jako král, který opouští své poražené království, putuj sám, jako osamělý slon lesem Mátanga",
  "330": "putovat sám je lepší, není radno spolčovat se s pošetilci, proto putuj sám, nekonaje zlo, bezstarostný, jako osamělý slon lesem Mátanga",
  "331": "ve vzniklé nouzi mít přátele je štěstím, spokojenost s jakýmikoliv potřebami je štěstím, zásluhy na konci života jsou štěstím, opuštění veškeré strasti je štěstím",
  "332": "štěstím ve světě je úcta k matce, stejně tak úcta k otci je štěstím, štěstím ve světě je úcta k asketům, stejně tak úcta k bráhmanům je štěstím",
  "333": "štěstím je ctnostný život až do stáří, štěstím je upevněná důvěra, štěstím je nabytí moudrosti, nekonání zla je štěstím",
  "chap24": "Toužení",
  "334": "u člověka, který žije nedbale, toužení vzrůstá jako popínavá rostlina, plave jen sem a tam [z života do života], toužebně vyhledávaje plody, jako opice v lese",
  "335": "koho přemůže toto hrubé a lepivé toužení ve světě, u toho trápení narůstá jako tráva po dešti",
  "336": "kdo však přemůže toto hrubé toužení ve světě, z něhož je těžké se vymanit, od toho trápení odpadne jako kapky vody z lotosového květu",
  "337": "toto vám říkám: blaze vám, zde shromážděným, kteří vytrhnete kořen svého toužení, tak jako sběrač vonných kořínků trávu, nedopusťte aby vástak jako říční proud rákosMára lámal [ničil] znovu a znovu",
  "338": "jako nepoškozený silný kořen uťatého stromu znovu vyroste, tak ze sklonu k toužení, není-li vykořeněn, vyvstává toto utrpení, znovu a znovu",
  "339": "u koho je šestatřicet proudů [smyslnosti] vyvěrajících z toho, co je příjemné, mohutných, toho tento tok odplaví [do strastného stavu], tyto zhoubné názory a myšlenky [motivy] spočívající na vášni",
  "340": "tyto proudy tečou všude, popínavé rostliny [vášně] vypučí, když se uchytí, vidíš-li jak se taková popínavá rostlina rodí, její kořen moudře vytrhni",
  "341": "uvolněné a bez zábran jsou lidské radosti, ti, kdo hledají štěstí v příjemnostech, vskutku tito lidé podléhají zrození a stárnutí",
  "342": "touhu upřednostňující lidé se chvějí jako polapený zajíc, spoutáni a svázáni pouty, přicházejí k utrpení, znovu a znovu, po dlouhou dobu",
  "343": "touhu upřednostňující lidé se chvějí jako polapený zajíc, proto by měl tuto touhu odstranit mnich, který si přeje být oproštěn od vášně",
  "344": "když vymítil podrost, ale zůstal obklopen lesem [žádostí], ač mohl být vysvobozen z lesa, znovu se do lesa vrací, pohleď na tohoto člověka, ač mohl být vysvobozen, znovu se ke svým poutům vrací",
  "345": "není pevné pouto, říkají mudrcové, které je ze železa, ze dřeva či z travních vláken, je to zalíbení v klenotech a špercích toužení po ženách a dětech [potomcích]",
  "346": "pevné je to pouto, říkají mudrcové, které stahuje dolů, je poddajné a je těžké se z něj vyprostit, proto jej odetli a odešli do bezdomoví, prosti toužení opustili příjemné smyslné požitky",
  "347": "ti, kdo se radují z vášně, padají do jejího proudu, jako pavouk do sítě, kterou sám vyrobil, proto ji mudrci odetli a odešli, prosti toužení opustili veškerou strast",
  "348": "oprosti se od toho, co je před tebou i od toho, co je za tebou, oprosti se i od toho, co je mezi tím a překroč bytí, s myslí od všeho osvobozenou již nepůjdeš znovu vstříc zrození a stárnutí",
  "349": "u člověka s rozrušenými myšlenkami a silnou vášní, který nazírá jen [tělesnou] krásu, velmi vzrůstá toužení, jen si tím upevňuje pouta",
  "350": "kdo se však těší utišováním myšlenek, a medituje nad [tělesnou] odporností, vždy uvědomělý, ten učiní konec, ten odetne Márova pouta",
  "351": "kdo došel cíle a je beze strachu, prost toužení a bez poskvrny, ten vytrhl šípy bytí a je vtělen naposledy",
  "352": "kdo je prost toužení a bez lpění, je obeznámen s textyse skladbu slovzná které předcházejí a které je následují, ten je vtělen naposledy, o tom se říká, že je velký člověk s velkou moudrostí",
  "353": "všechno jsem přemohl, všechno jsem poznal, na žádných věcech [stavech] nelpím, všeho jsem zanechal a jsem osvobozen odstraněním toužení: sám jsem to přímo poznal, koho bych měl nazvat svým učitelem ?",
  "354": "všechny dary předčí dar Dhammy, všechny chutě předčí chuť Dhammy, všechny radosti předčí radost z Dhammy, odstranění toužení předčí všechno utrpení",
  "355": "požitky [bohatství] ničí nemoudrého člověka, ne toho, kdo hledá druhý břeh, z touhy po požitcích [bohatství] nemoudrý člověk ničí ostatní i sebe",
  "356": "plevel ničí pole, vášeň ničí tyto lidi, prototěm, kdo jsou prosti vášnědávání přináší velké plody",
  "357": "plevel ničí pole, nenávist ničí tyto lidi, prototěm, kdo jsou prosti nenávistidávání přináší velké plody",
  "358": "plevel ničí pole, zaslepenost ničí tyto lidi, prototěm, kdo jsou prosti zaslepenostidávání přináší velké plody",
  "359": "plevel ničí pole, žádostivost ničí tyto lidi, prototěm, kdo jsou prosti žádostivostidávání přináší velké plody",
  "chap25": "Mnich",
  "360": "ovládat své oko [zrak] je dobré, je dobré ovládat své ucho [sluch], ovládat svůj nos [čich] je dobré, je dobré ovládat svůj jazyk [chuť]",
  "361": "ovládat své tělo je dobré, je dobré ovládat svou řeč, ovládat svou mysl je dobré, je dobré zcela se ovládat, zcela se kontrolující mnich od veškeré strasti se osvobodí",
  "362": "kdo ukázní své ruce, ukázní své nohy, ukázní svou řeč, nanejvýš se ukáznív niterné radosti, soustředěný a spokojený v samotěten je nazýván mnichem",
  "363": "mnich, který ukázní svá ústa, recituje bez rozrušení [nepovýšeně] a objasňuje smysl Dhammysladká je jeho řeč",
  "364": "Dhammou se těšící, z Dhammy se radující, Dhammu zkoumající, Dhammu si připomínající mnich od dobré Dhammy neodpadne",
  "365": "nemysli na vlastní zisk, nežij v závisti vůči ostatním, mnich, který závidí ostatním, soustředění nedosáhne",
  "366": "i když mnich nenabyl zisku, na vlastní zisk nemyslí, toho i bohové chválí, kdo žije čistě a nepolevuje v úsilí",
  "367": "jakékoli jméno-a-hmotu, kdo nepovažuje za své vlastní, a kvůli tomu, co není se netrápí, ten je nazýván mnichem",
  "368": "v laskavosti prodlévající mnich, povznešený Buddhovým učením, dosáhne stavu míru : štěstí utišení formací",
  "369": "vyprázdni, mnichu, tento člun, prázdný pro tebe bude lehčí, odetneš-li vášeň a nenávist, dojdeš tím k odpoutání",
  "370": "odetni pět [nižších pout], zanech pět [vyšších pout] a rozviň přednostně pět [řídících schopností], mnich, který překonal pět připoutaností je nazýván 'ten, kdo překročil záplavu'",
  "371": "cvič meditační pohroužení, mnichu, nebuď nedbalý, nenech svou mysl potulovat u pramenů smyslnosti, nespolkni z nedbalosti tuto žhavou železnou kouli, aby ses nespálil a nenaříkal : 'to je utrpení'",
  "372": "není meditační pohroužení u toho, kdo postrádá moudrost, není moudrost u toho, kdo postrádá meditační pohroužení, kdo je však obdařen meditačním pohroužením i moudrostí, ten je již v blízkosti odpoutání",
  "373": "do prázdného příbytku vstupuje mnich, který má mysl naplněnou mírem, zakouší radost, kterou nezakouší obyčejní lidé, ten, kdo správně a jasně vidí Dhammu",
  "374": "kdo správně pozná [zakusí] jakým způsobem osobnostní skupiny vznikají a zanikají, ten získá nadšení a radost, neboť tím pozná bezsmrtný stav",
  "375": "toto jsou první kroky moudrého mnicha, zde [v tomto učení] : střežení svých smyslů a spokojenost, sebekontrola podle pravidel cvičení, sdružování se s dobrými přáteli, čistý život a nepolevování v úsilí,",
  "376": "měl by mít přátelské způsoby a být zkušený v jednání, tím bude naplněn radostí a učiní konec utrpení",
  "377": "jako jasmín květů uvadlých se zbavuje, tak vášně a nenávisti zcela se zbavte, mniši",
  "378": "kdo má mírné [klidné] tělo a mírnou řeč, je mírný a dobře soustředěný, mnich, který opustil světské návnady, ten je nazýván 'umírněný'",
  "379": "sám sebe napravuj [napomínej], sám sebe zkoumej, když střeží sám sebe a je uvědomělý, bude mnich prodlévat blaženě",
  "380": "každý je sám sobě ochráncem, každý je sám sobě vůdcem, proto bys měl ukáznit sám sebe, jako chovatel svého skvělého koně",
  "381": "radostí naplněný mnich, povznešený Buddhovým učením, dosáhne stavu míru : štěstí utišení formací",
  "382": "když mladý mnich bojuje [usiluje] v Buddhově učení, ozáří tento svět, jako z mraků vynořivší se měsíc",
  "chap26": "Bráhman",
  "383": "s odvahou odetni [zastav] proud [vznikání] a zavrhni smyslové požitky, bráhmane, s poznáním ukončení formací poznáš to, co je nestvořené, bráhmane",
  "384": "když tyto dvě věci bráhman překročí, pak všechna jeho pouta dojdou k ukončeníu toho, kdo je vědoucí",
  "385": "pro koho již onen svět ani tento svět, ani onen-i-tento svět neexistuje [není k nalezení], je prostý úzkosti a zbavený pout, toho nazývám bráhmanem",
  "386": "kdo dlí bez poskvrn v meditačním pohroužení, kdo splnil svůj úkol a je prostý zákalů, kdo dosáhl nejvyššího cíle, toho nazývám bráhmanem",
  "387": "slunce září ve dne, měsíc svítí v noci, bojovník září ve své zbroji, bráhman září v meditačním pohroužení, avšak po celý [každý] den i noc září svým jasem Probuzený",
  "388": "'bráhman' proto, že se zbavil zla, 'asketa' proto je někdo nazýván, že žije správně, že opustil vlastní poskvrnění, proto je někdo nazýván 'ten, kdo opustil [odešel]'",
  "389": "nechť nikdo neudeří bráhmana a bráhman nechť nepovolí svému hněvu, hanba tomu, kdo napadne bráhmana, větší hanba, když ten povolí svému hněvu",
  "390": "nic není pro bráhmana lepší než pevně ovládaná mysl vůči tomu, co je milé, a do jaké míry se odvrátí od ubližování, do té míry se utiší jeho utrpení",
  "391": "kdo tělesně, slovně a mentálně nekoná špatné skutky, ovládá se v těchto třech způsobech, toho nazývám bráhmanem",
  "392": "od koho jsi byl poučen v Dhammě, vyložené dokonale Probuzeným, toho chovej v náležité úctě, jako bráhman obětní oheň",
  "393": "ani splétáním vlasů, ani rodem ani zrozením se nikdo nestane bráhmanem, v kom je však pravda a Dhamma, ten je čistým, ten je bráhmanem",
  "394": "k čemu je ti splétání vlasů, nemoudrý člověče, k čemu je ti plášť z antilopí kůže?, uvnitř jsi zamotaný, navenek uhlazený",
  "395": "kdo se obléká do odhozených hadrů, je vyhublý až mu vystupují žíly a osamotě dlí v lesích v meditačním pohroužení, toho nazývám bráhmanem",
  "396": "nenazývám někoho bráhmanem podle toho z jakého lůna, z jaké matky se zrodil, nazýván ctěným učitelem [vykladačem] je ten, kdo nic nemákdo na ničem nelpí, toho nazývám bráhmanem",
  "397": "kdo odetnul všechna pouta, není rozrušený a je oproštěn od připoutanosti, toho nazývám bráhmanem",
  "398": "kdo odetnul popruh a řemen, otěž a uzdu, odstranil závoru a je probuzený, toho nazývám bráhmanem",
  "399": "kdo napadení, rány i pouta snáší prost zloby a jeho silou je síla trpělivosti, toho nazývám bráhmanem",
  "400": "kdo je prost hněvu a dbalý svých povinností, dbalý ctnosti a prost pýchy, kdo je zkrocený a je vtělen naposledy, toho nazývám bráhmanem",
  "401": "jako voda na lotosovém listě či hořčičné semínko na hrotu jehly, kdo na smyslových požitcích neulpí, toho nazývám bráhmanem",
  "402": "kdo vzhledem k utrpení poznává, že ho právě zde, sám pro sebe ukončil, kdo odložil břemeno a je odpoután, toho nazývám bráhmanem",
  "403": "mudrce s hlubokou moudrostí, který rozezná co je stezka a co není stezka, který dosáhl nejvyššího cíle, toho nazývám bráhmanem",
  "404": "kdo se nesdružuje s hospodáři ani s poutníky bez domova, kdo žije v bezdomoví a má málo přání, toho nazývám bráhmanem",
  "405": "kdo zanechal násilí [odložil hůl] vůči živým bytostem, ať bázlivým či statečným, kdo nezabíjí ani nenavádí ostatní k zabíjení, toho nazývám bráhmanem",
  "406": "kdo je prost nepřátelství mezi nepřáteli, mezi násilníky je umírněný [odpoutaný] a mezi ulpívajícími je prost lpění, toho nazývám bráhmanem",
  "407": "od koho vášeň i nenávist, domýšlivost i pohrdavost odpadla jako hořčičné semínko z hrotu jehly, toho nazývám bráhmanem",
  "408": "kdo ne-hrubá, poučná a pravdivá slova pronáší, kdo nikoho neuráží, toho nazývám bráhmanem",
  "409": "kdo zdeať dlouhé či krátké, malé či velké, krásné či ošklivéve světě nebere nic nedarovaného, toho nazývám bráhmanem",
  "410": "u koho není k nalezení touha po tomto světě či po onom světě [po smrti], kdo je zbaven touhy a je odpoutaný, toho nazývám bráhmnem",
  "411": "u koho není k nalezení místo jeho lpění a je prost pochybností díky konečnému poznání, kdo dosáhl hlubiny bezsmrtnosti, toho nazývám bráhmanem",
  "412": "kdo zde [v tomto světě] dobro i zlo, obě tato lpění překonal a je prost trápení, bez poskvrny, čistý, toho nazývám bráhmanem",
  "413": "kdo je jako měsíc, neposkvrněný a čistý, čirý a klidný, kdo zcela odstranil zalíbení v bytí, toho nazývám bráhmanem",
  "414": "kdo tuto nebezpečnou a obtížnou cestu, koloběh životů a zaslepenost překonal, kdo překročil na druhý břeh a dlí v meditačním pohroužení, kdo je prost žádostí, prost pochybností, odpoutaný skrze neulpívání, toho nazývám bráhmanem",
  "415": "kdo zde, opustiv smyslné požitky, odejde z domova do bezdomoví, kdo zcela ukončil [odstranil] smyslné bytí, toho nazývám bráhmanem",
  "416": "kdo zde, opustiv toužení, odejde z domova do bezdomoví, kdo zcela ukončil [odstranil] toužení po bytí, toho nazývám bráhmanem",
  "417": "kdo opustil lidská pouta a překonal i pouta nebeská, kdo je zbaven všech pout, toho nazývám bráhmanem",
  "418": "kdo opustil libost i nelibost, kdo je vychladlý a prostý přivlastňování, kdo je hrdinou, jenž přemohl celý svět, toho nazývám bráhmanem",
  "419": "kdo zná zanikání [odcházení] bytostí a jejich znovuvyvstávání, v celistvosti, kdo je bez lpění, blažený a probuzený, toho nazývám bráhmanem",
  "420": "ten, jehož směr [místo určení] neznají bohové, nebešťané ani lidé, kdo je oproštěný od zákalů, zasloužilý, toho nazývám bráhmanem",
  "421": "pro koho je minulost, budoucnost i to, co je mezi tím nicotou, kdo na ničem nelpí, toho nazývám bráhmanem",
  "422": "kdo je vůdce a ušlechtilý hrdina, kdo je velkým zřecem, jenž nad vším zvítězil, kdo je prost žádostí, očištěný od zla a probuzený, toho nazývám bráhmanem",
  "423": "kdo své dřívější životy poznal a nebeské světy i místa utrpení uzřel, kdo ukončení zrozování dosáhl a je mudrcem s dokonalým přímým poznáním, kdo dovršil vše, co lze dovršit, toho nazývám bráhmanem"
};
